import asyncio
import logging
from typing import Optional

from .. import BaseDriver, DriverCapability, DriverHealth, DriverMetrics, InferenceRequest, InferenceResponse, EmbeddingRequest, EmbeddingResponse

logger = logging.getLogger("aether.ai.local_driver")


class LocalDriver(BaseDriver):
    """Driver for local LLM inference using llama.cpp server."""

    def __init__(self, model_id: str, base_url: str, **config):
        super().__init__(model_id, **config)
        self.base_url = base_url
        self.client = None
        self._capabilities = [DriverCapability.CHAT, DriverCapability.COMPLETION]

    @property
    def driver_type(self) -> str:
        return "local"

    def capabilities(self) -> list[DriverCapability]:
        return self._capabilities

    async def initialize(self) -> None:
        from httpx import AsyncClient
        self.client = AsyncClient(base_url=self.base_url, timeout=30.0)
        logger.info(f"Local driver initialized with base_url={self.base_url}")

    async def health_check(self) -> DriverHealth:
        if not self.client:
            return DriverHealth(status="error", message="Not initialized")

        try:
            start_time = asyncio.get_event_loop().time()
            response = await self.client.get("/health")
            end_time = asyncio.get_event_loop().time()
            latency = (end_time - start_time) * 1000

            if response.status_code == 200:
                return DriverHealth(status="healthy", latency_ms=latency)
            else:
                return DriverHealth(status="error", message=f"Health check failed: {response.status_code}", latency_ms=latency)
        except Exception as e:
            return DriverHealth(status="error", message=str(e))

    async def infer(self, request: InferenceRequest) -> InferenceResponse:
        if not self.client:
            raise RuntimeError("Local driver not initialized")

        try:
            # Prepare request body
            body = {
                "messages": request.messages,
                "temperature": request.temperature,
                "max_tokens": request.max_tokens,
                "stream": False,
            }

            start_time = asyncio.get_event_loop().time()
            response = await self.client.post("/chat/completions", json=body)
            end_time = asyncio.get_event_loop().time()
            latency = (end_time - start_time) * 1000

            if response.status_code == 200:
                data = response.json()
                result = InferenceResponse(
                    model=self.model_id,
                    driver_type=self.driver_type,
                    content=data["choices"][0]["message"]["content"],
                    finish_reason=data["choices"][0]["finish_reason"],
                    usage=data.get("usage", {}),
                    latency_ms=latency,
                )
                self.record_success(latency, result.usage.get("total_tokens", 0))
                return result
            else:
                error_msg = f"Inference failed: {response.status_code}"
                self.record_failure(error_msg)
                raise RuntimeError(error_msg)
        except Exception as e:
            error_msg = f"Inference failed: {str(e)}"
            self.record_failure(error_msg)
            raise

    async def infer_stream(self, request: InferenceRequest):
        if not self.client:
            raise RuntimeError("Local driver not initialized")

        try:
            # Prepare request body
            body = {
                "messages": request.messages,
                "temperature": request.temperature,
                "max_tokens": request.max_tokens,
                "stream": True,
            }

            response = await self.client.post("/chat/completions", json=body, stream=True)

            if response.status_code == 200:
                async for chunk in response.aiter_lines():
                    if chunk.startswith("data: "):
                        data = chunk[6:]
                        if data != "[DONE]":
                            # Parse the chunk
                            import json
                            try:
                                chunk_data = json.loads(data)
                                if "choices" in chunk_data:
                                    delta = chunk_data["choices"][0].get("delta", {})
                                    if "content" in delta:
                                        yield delta["content"]
                            except json.JSONDecodeError:
                                pass
            else:
                error_msg = f"Streaming inference failed: {response.status_code}"
                self.record_failure(error_msg)
                raise RuntimeError(error_msg)
        except Exception as e:
            error_msg = f"Streaming inference failed: {str(e)}"
            self.record_failure(error_msg)
            raise

    async def embed(self, request: EmbeddingRequest) -> EmbeddingResponse:
        if not self.client:
            raise RuntimeError("Local driver not initialized")

        try:
            body = {
                "input": request.texts,
                "model": self.model_id,
            }

            response = await self.client.post("/embeddings", json=body)

            if response.status_code == 200:
                data = response.json()
                result = EmbeddingResponse(
                    embeddings=[e["embedding"] for e in data["data"]],
                    model=self.model_id,
                    driver_type=self.driver_type,
                    usage=data.get("usage", {}),
                )
                return result
            else:
                error_msg = f"Embedding failed: {response.status_code}"
                self.record_failure(error_msg)
                raise RuntimeError(error_msg)
        except Exception as e:
            error_msg = f"Embedding failed: {str(e)}"
            self.record_failure(error_msg)
            raise

    async def get_available_models(self) -> list[str]:
        # For now, return just our model
        return [self.model_id]

    async def shutdown(self) -> None:
        if self.client:
            await self.client.aclose()
            self.client = None
        logger.info("Local driver shutdown")

