from __future__ import annotations

import asyncio
import httpx
import logging
from typing import Optional, List

from ..drivers.base import BaseDriver, DriverCapability, DriverHealth, DriverMetrics, InferenceRequest, InferenceResponse, EmbeddingRequest, EmbeddingResponse

logger = logging.getLogger("aether.ai.openai_driver")


class OpenAIDriver(BaseDriver):
    """Driver for OpenAI API inference."""

    def __init__(self, model_id: str, api_key: str = "", base_url: str = "https://api.openai.com/v1", **config):
        super().__init__(model_id, **config)
        self.api_key = api_key
        self.base_url = base_url
        self._client: Optional[httpx.AsyncClient] = None
        self._capabilities = [DriverCapability.CHAT, DriverCapability.COMPLETION, DriverCapability.EMBEDDING]

    @property
    def driver_type(self) -> str:
        return "openai"

    def capabilities(self) -> list[DriverCapability]:
        return self._capabilities

    async def initialize(self) -> None:
        self._client = httpx.AsyncClient(timeout=30.0)
        self._last_health = await self.health_check()

    async def health_check(self) -> DriverHealth:
        try:
            if not self._client:
                return DriverHealth(status="error", message="Not initialized")

            resp = await self._client.get(f"{self.base_url}/models", headers={"Authorization": f"Bearer {self.api_key}"})
            if resp.status_code == 200:
